module RefModule(  
    input clk,  
    input reset,  
    input [4:0] audio_in,  
    output reg [4:0] audio_out  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            audio_out <= 5'b00000;  
        else  
            audio_out <= audio_in >> 1;  
    end  
endmodule
